INSERT INTO projects (slug, title, subtitle, description, category, order_index) VALUES ('genfact', 'GenFact', 'Logiciel de facturation automatisée', 'Logiciel Python automatisant la génération de factures mensuelles via l''API Sellsy pour Coliback.', 'ingénierie logiciel', 4);
INSERT INTO pages (slug, title, type) VALUES ('genfact', 'GenFact', 'projet');
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'header_title', 'h1', 'GenFact', 'hero', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'header_breadcrumb', 'label', 'home / projets', 'hero', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'intro_p1', 'paragraph', 'Durant mes missions, Stéphane Gatel, directeur de Coliback a identifié un besoin critique concernant la facturation mensuelle des e-commerçants via la suite Sellsy, un CRM et outil de facturation incontournable pour l''entreprise. Coliback gère deux activités principales : le "Flux Aller" (préparation et expédition de produits) et le "Flux Retour" (gestion des commandes défectueuses, incomplètes ou des produits manquants).\n\nJusqu''alors, la création des factures pour ces deux flux était effectuée de manière totalement manuelle par un collaborateur (Stéphane). Ce processus chronophage, répétitif et sans réelle valeur ajoutée prenait entre 3 et 4 jours pleins par mois.\n\nJ''ai donc pris l''initiative de concevoir et développer GenFact, un logiciel d''automatisation capable de scrapper des fichiers Excel métiers et d''interagir directement avec l''API de Sellsy pour générer ces factures.', 'intro', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch1_title', 'h2', '1. Objectifs du projet', 'objectifs', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch1_intro', 'paragraph', 'L''enjeu principal était de transformer un processus métier laborieux en un pipeline logiciel fluide et sécurisé. Pour y parvenir, j''ai défini deux objectifs majeurs :', 'objectifs', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch1_1_title', 'h3', '1.1. Concevoir et développer un logiciel performant, maintenable et évolutif', 'objectifs', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch1_1_text', 'paragraph', 'Il s''agissait de créer une application capable d''accélérer drastiquement la production des factures des e-commerçants.\n\nTechniquement, cela impliquait de développer un pipeline (ETL métier) en Python, capable de lire des dossiers d''entrée contenant des fichiers .xlsx, d''en extraire les données pertinentes et de communiquer via l''API REST v2 de Sellsy pour générer les documents.', 'objectifs', 4);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch1_2_title', 'h3', '1.2. Concevoir des validateurs métiers robustes', 'objectifs', 5);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch1_2_text', 'paragraph', 'L''automatisation ne devait pas se faire au détriment de la qualité.\n\nIl était impératif d''éviter de poster des factures erronées, doublonnées ou corrompues dans le système comptable.\n\nLe programme devait donc intégrer des contrôles stricts (mapping des références, vérification des totaux, etc.) avant de procéder à tout appel d''écriture (POST) sur l''API.', 'objectifs', 6);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch2_title', 'h2', '2. CONTEXTE HUMAIN ET TECHNIQUE', 'contexte', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch2_1_title', 'h3', '2.1. Les acteurs du projet', 'contexte', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch2_1_intro', 'paragraph', 'Ce projet a nécessité une forte collaboration transverse. En tant que développeur de la solution, j''ai travaillé en étroite collaboration avec :', 'contexte', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch2_1_item1', 'list_item', 'Le Directeur Technique et Opérationnel (DTO) pour la validation de l''architecture.', 'contexte', 4);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch2_1_item2', 'list_item', 'Le Directeur de l''Exploitation (DEO) pour la conformité métier.', 'contexte', 5);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch2_1_item3', 'list_item', 'L''utilisateur final (Stéphane), qui traitait ces données manuellement, pour comprendre son workflow et ses points de douleur.', 'contexte', 6);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch2_1_item4', 'list_item', 'Les clients e-commerçants, bénéficiaires finaux de ces factures.', 'contexte', 7);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch2_2_title', 'h3', '2.2. Le contexte technique', 'contexte', 8);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch2_2_text', 'paragraph', 'L''entreprise utilise exclusivement la suite CRM Sellsy pour sa gestion financière et sa comptabilité.\n\nC''est une solution hermétique, et toute la facturation était réalisée manuellement en local.\n\nL''enjeu technique était donc de s''interfacer avec ce système fermé via son API V2, en gérant de manière sécurisée l''authentification (tokens OAuth2 / Bearer) et le certificat SSL, que l''outil soit lancé en environnement de développement ou sous forme d''exécutable packagé (PyInstaller).', 'contexte', 9);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch3_title', 'h2', '3. ENJEUX ET RISQUES', 'enjeux', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch3_1_title', 'h3', '3.1. Les enjeux', 'enjeux', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch3_1_text', 'paragraph', 'Humains et productivité : Permettre un gain de temps et d''effort massif, et diminuer la charge mentale liée à une tâche ingrate.\n\nTechniques : Développer une solution parfaitement compatible avec l''écosystème Sellsy.\n\nOpérationnels : Offrir une visualisation claire des traitements. J''ai donc implémenté un système de logs détaillé (logger.info, logger.error stockés dans rapport_logs.log) et la génération d''un rapport structuré (result.json) permettant de savoir instantanément quelle facture a été créée, et laquelle a échoué avec le motif précis de l''erreur.\n\nÉvolutifs : Proposer une architecture modulable, initialement prévue pour le Flux Aller, mais rapidement adaptable au Flux Retour.', 'enjeux', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch3_2_title', 'h3', '3.2. Les risques identifiés', 'enjeux', 4);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch3_2_text', 'paragraph', 'Risque d''intégrité des données : Produire en masse des factures erronées directement dans la base de production Sellsy, ce qui aurait imposé une suppression manuelle fastidieuse et faussé la comptabilité.\n\nRisque de sécurité : Porter atteinte à l''intégrité de l''espace Coliback dans Sellsy en créant des failles (mauvaise gestion des tokens d''authentification).\n\nRisque architectural : Créer un script "jetable" non scalable au lieu d''une véritable application maintenable.', 'enjeux', 5);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_title', 'h2', '4. ÉTAPES DU PROJET ET RÉALISATION TECHNIQUE', 'realisation', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_intro', 'paragraph', 'La conduite de ce projet a respecté un cycle de développement logiciel rigoureux.', 'realisation', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_1_title', 'h3', '4.1. Rédaction du cahier des charges', 'realisation', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_1_text', 'paragraph', 'Définition précise du besoin, du périmètre d''action, de la stack technique (Python, API REST, expressions régulières pour l''extraction de chaînes de caractères), des contraintes de temps et du workflow utilisateur.', 'realisation', 4);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_2_title', 'h3', '4.2. Veille technologique et informative sur l''API Sellsy', 'realisation', 5);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_2_text', 'paragraph', 'J''ai étudié la documentation de l''API V2 de Sellsy pour comprendre les endpoints disponibles, le système de pagination des requêtes (notamment pour récupérer les références d''articles via GET /v2/items), et les règles de constitution du payload (charge utile) JSON attendu pour la création de factures.', 'realisation', 6);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_3_title', 'h3', '4.3. Conception d''une architecture orientée services (SOA) et gestion de flux', 'realisation', 7);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_3_text', 'paragraph', 'J''ai structuré l''application autour d''un pipeline clair. Le logiciel scrute un dossier d''entrée (invoices_input). Les fichiers .xlsx sont traités unitairement.\n\nEn cas de succès (facture validée par l''API et lien PDF généré), le fichier source est automatiquement isolé vers un dossier d''archives (generated_invoices) à l''aide de la librairie shutil de Python, assurant une parfaite traçabilité du flux.', 'realisation', 8);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_4_title', 'h3', '4.4. Modélisation UML', 'realisation', 9);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_4_text', 'paragraph', 'Conception du diagramme d''objets pour modéliser le système, séparant clairement les responsabilités (ex: classe Invoice pour gérer la logique de facturation, classe ReferenceSellsy pour la récupération du catalogue, fonctions utilitaires pour l''extraction de noms).', 'realisation', 10);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_5_title', 'h3', '4.5. Développement du programme (MVP) connecté à l''API', 'realisation', 11);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_5_text', 'paragraph', 'Le programme identifie la société cible non pas en lisant l''Excel, mais en extrayant intelligemment le nom de l''entreprise depuis le nommage standardisé du fichier via une expression régulière (FactureSynthese---).\n\nIl effectue ensuite une requête de recherche (POST /v2/companies/search) pour lier cette donnée aux identifiants internes de Sellsy.', 'realisation', 12);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_6_title', 'h3', '4.6. Implémentation des validateurs (Sécurité métier)', 'realisation', 13);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_6_text', 'paragraph', 'C''est ici qu''intervient la logique de fiabilisation. Avant tout envoi à l''API (post_payload), le programme vérifie via la méthode buildPayload que les totaux extraits du fichier Excel correspondent aux calculs internes.\n\nEn cas de non-correspondance, ou si une référence comptable n''est pas trouvée, la création de la facture est bloquée, l''erreur est logguée, et le fichier reste dans le dossier d''entrée.', 'realisation', 14);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_7_title', 'h3', '4.7. Phase de tests et debugging', 'realisation', 15);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_7_text', 'paragraph', 'J''ai mis en place un système de traitement simulé (run_processing_mock) pour éprouver la logique sans impacter la base Sellsy.\n\nJ''ai ensuite mené des tests réels avec le CEO pour valider la correspondance des références de services, le format des données, l''intitulé des factures générées et le bon nommage des documents.', 'realisation', 16);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_8_title', 'h3', '4.8. Évolution vers le Flux Retour', 'realisation', 17);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch4_8_text', 'paragraph', 'L''architecture modulaire et la conception objet du code ont permis d''adapter très rapidement le système pour qu''il prenne également en charge les spécificités du Flux Retour, validant ainsi la scalabilité de la solution.', 'realisation', 18);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch5_title', 'h2', '5. MÉTHODOLOGIE ADOPTÉE', 'methodologie', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch5_text', 'paragraph', 'Pour ce projet aux exigences claires et séquentielles (on ne peut pas générer la facture sans avoir validé l''extraction des données), j''ai opté pour la méthodologie Waterfall (Cascade). Cette approche était la plus pertinente :', 'methodologie', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch5_item1', 'list_item', 'Définition exhaustive des besoins.', 'methodologie', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch5_item2', 'list_item', 'Conception du système et des workflows (diagrammes, maquettes de flux).', 'methodologie', 4);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch5_item3', 'list_item', 'Développement complet (Extraction, mapping API, Payload, Déplacement de fichiers).', 'methodologie', 5);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch5_item4', 'list_item', 'Tests métiers (vérification des références et montants).', 'methodologie', 6);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch5_item5', 'list_item', 'Déploiement métier.', 'methodologie', 7);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch6_title', 'h2', '6. FIN DE PROJET ET PERSPECTIVES', 'conclusion', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'ch6_text', 'paragraph', 'Aujourd''hui, GenFact est une solution robuste et fiable, utilisée en production depuis plus d''un an sur l''ensemble des facturations (Flux Aller et Flux Retour).\nLes résultats sont concrets : le processus de facturation mensuel de Coliback est passé de 3 à 4 jours de travail manuel intensif à seulement une demi-journée de supervision. Les risques d''erreurs de saisie ont été drastiquement réduits, et le collaborateur en charge a pu réallouer son temps à des tâches à plus forte valeur ajoutée.\n\nMon évolution et perspectives :\n- Sur le plan technique, ce projet m''a permis de maîtriser l''intégration d''API complexes en Python, la sécurisation des requêtes HTTPS en environnement packagé, et la mise en place de pipelines de données (ETL).\n\n- Pour l''avenir, la prochaine évolution logique de cet outil, actuellement exécuté en console (CLI) avec lecture de logs, serait le développement d''une Interface Utilisateur Graphique (GUI). Cela permettrait de rendre les utilisateurs finaux totalement autonomes dans le lancement des traitements et la lecture du result.json directement via un tableau de bord, sans aucune intervention technique.', 'conclusion', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('genfact', 'projects_title', 'h2', 'projets', 'projets', 1);
